constexpr std::array<int, 8> kAnchorMidiNotes{24, 36, 48, 60, 72, 84, 96, 108}; // C1..C8

template<int N>
constexpr HarmonicIntensities::Spectrum ToSpectrum(const float (&values)[N])
{
  static_assert(N == HarmonicIntensities::kNumHarmonics, "Each spectrum must have exactly kNumHarmonics values");

  HarmonicIntensities::Spectrum spectrum{};
  for(int i = 0; i < HarmonicIntensities::kNumHarmonics; ++i)
    spectrum[i] = values[i];

  return spectrum;
}

